"""A readable parser for standard 5-field cron expressions.

The public entry point is `parse_cron`, which turns an expression like
"0 12 * * 1-5" into a `CronSchedule`. The schedule exposes the expanded
values for every field and a `describe()` method that renders a
human-readable English summary.

The code is organised top-down: high-level orchestration first, then the
shared single-field parser, then the description helpers, then small utilities.
"""

from __future__ import annotations

from dataclasses import dataclass

# --------------------------------------------------------------------------- #
# Field definitions
# --------------------------------------------------------------------------- #

DAY_NAMES: list[str] = [
    "Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday",
]

MONTH_NAMES: list[str] = [
    "January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December",
]


@dataclass(frozen=True)
class FieldSpec:
    """Describes one position in a cron expression (e.g. the "hour" field)."""

    name: str
    min_value: int
    max_value: int


# The five fields, in the order they appear in a cron expression.
FIELD_SPECS: list[FieldSpec] = [
    FieldSpec("minute", 0, 59),
    FieldSpec("hour", 0, 23),
    FieldSpec("day_of_month", 1, 31),
    FieldSpec("month", 1, 12),
    FieldSpec("day_of_week", 0, 6),
]


class CronParseError(ValueError):
    """Raised when a cron expression cannot be parsed."""


# --------------------------------------------------------------------------- #
# Parsed result
# --------------------------------------------------------------------------- #

@dataclass(frozen=True)
class CronField:
    """A single parsed field: its raw text, expanded values, and spec."""

    raw: str
    values: list[int]
    spec: FieldSpec

    @property
    def is_wildcard(self) -> bool:
        return self.raw == "*"


@dataclass(frozen=True)
class CronSchedule:
    """A fully parsed cron expression."""

    minute: CronField
    hour: CronField
    day_of_month: CronField
    month: CronField
    day_of_week: CronField

    def describe(self) -> str:
        """Return a human-readable English description of the schedule."""
        return _describe_schedule(self)


# --------------------------------------------------------------------------- #
# Top-level parsing
# --------------------------------------------------------------------------- #

def parse_cron(expression: str) -> CronSchedule:
    """Parse a standard 5-field cron expression into a `CronSchedule`.

    Raises `CronParseError` for malformed or out-of-range input.
    """
    tokens = _split_into_five_fields(expression)
    fields = [_parse_field(token, spec) for token, spec in zip(tokens, FIELD_SPECS)]
    minute, hour, day_of_month, month, day_of_week = fields
    return CronSchedule(minute, hour, day_of_month, month, day_of_week)


def _split_into_five_fields(expression: str) -> list[str]:
    """Split an expression into exactly five whitespace-separated tokens."""
    tokens = expression.split()
    if len(tokens) != 5:
        raise CronParseError(
            f"Expected 5 fields but got {len(tokens)}: {expression!r}"
        )
    return tokens


# --------------------------------------------------------------------------- #
# Single-field parsing (shared by all five fields)
# --------------------------------------------------------------------------- #

def _parse_field(token: str, spec: FieldSpec) -> CronField:
    """Parse one field (which may be a comma-separated list of parts)."""
    values: set[int] = set()
    for part in token.split(","):
        values.update(_parse_part(part, spec))
    return CronField(raw=token, values=sorted(values), spec=spec)


def _parse_part(part: str, spec: FieldSpec) -> list[int]:
    """Parse a single part of a field, e.g. `*`, `5`, `1-10`, `*/15`."""
    base, slash, step_text = part.partition("/")
    step = _parse_step(step_text, part) if slash else 1
    low, high = _parse_range(base, spec, has_step=bool(slash))
    return list(range(low, high + 1, step))


def _parse_range(base: str, spec: FieldSpec, has_step: bool) -> tuple[int, int]:
    """Resolve the inclusive `(low, high)` bounds for the base of a part.

    A bare value with a step (`5/15`) means "from 5 to the maximum",
    matching standard cron behaviour.
    """
    if base == "*":
        return spec.min_value, spec.max_value

    if "-" in base:
        return _parse_two_endpoints(base, spec)

    value = _parse_value(base, spec)
    return (value, spec.max_value) if has_step else (value, value)


def _parse_two_endpoints(base: str, spec: FieldSpec) -> tuple[int, int]:
    """Parse and validate a `low-high` range."""
    endpoints = base.split("-")
    if len(endpoints) != 2:
        raise CronParseError(f"Invalid range {base!r} in {spec.name}")

    low, high = (_parse_value(endpoints[0], spec), _parse_value(endpoints[1], spec))
    if low > high:
        raise CronParseError(f"Range start {low} is after end {high} in {spec.name}")
    return low, high


def _parse_value(text: str, spec: FieldSpec) -> int:
    """Parse a single integer and confirm it is within the field's range."""
    value = _parse_int(text, spec.name)
    if not spec.min_value <= value <= spec.max_value:
        raise CronParseError(
            f"Value {value} is out of range "
            f"[{spec.min_value}-{spec.max_value}] for {spec.name}"
        )
    return value


def _parse_step(text: str, part: str) -> int:
    """Parse the step that follows a `/` and confirm it is positive."""
    step = _parse_int(text, "step")
    if step <= 0:
        raise CronParseError(f"Step must be positive in {part!r}")
    return step


def _parse_int(text: str, context: str) -> int:
    """Parse an integer, raising a clear error on failure."""
    try:
        return int(text)
    except ValueError:
        raise CronParseError(f"Expected an integer for {context} but got {text!r}")


# --------------------------------------------------------------------------- #
# Description generation
# --------------------------------------------------------------------------- #

def _describe_schedule(schedule: CronSchedule) -> str:
    """Combine the time and calendar phrases into one English sentence."""
    phrases = [
        _describe_time(schedule.minute, schedule.hour),
        _describe_day_of_week(schedule.day_of_week),
        _describe_day_of_month_and_month(schedule.day_of_month, schedule.month),
    ]
    return " ".join(phrase for phrase in phrases if phrase)


def _describe_time(minute: CronField, hour: CronField) -> str:
    """Describe the minute and hour fields (the most varied part)."""
    minute_step = _wildcard_step(minute)
    hour_step = _wildcard_step(hour)

    if minute.is_wildcard and hour.is_wildcard:
        return "Every minute"

    if minute_step and hour.is_wildcard:
        return f"Every {minute_step} minutes"

    if hour_step and minute.values == [0]:
        return "Every hour, on the hour" if hour_step == 1 else \
            f"Every {hour_step} hours, on the hour"

    if len(minute.values) == 1 and len(hour.values) == 1:
        return _describe_single_time(hour.values[0], minute.values[0])

    return (
        f"At minute {_join_values(minute.values)} "
        f"past hour {_join_values(hour.values)}"
    )


def _describe_single_time(hour: int, minute: int) -> str:
    """Describe one exact time of day, e.g. `At 08:30` or `At midnight`."""
    if hour == 0 and minute == 0:
        return "At midnight"
    return f"At {hour:02d}:{minute:02d}"


def _describe_day_of_week(field: CronField) -> str:
    """Describe the day-of-week field, e.g. `on Monday through Friday`."""
    if field.is_wildcard:
        return ""

    names = [DAY_NAMES[value] for value in field.values]
    if _is_contiguous_range(field):
        return f"on {names[0]} through {names[-1]}"
    return f"on {_join_with_and(names)}"


def _describe_day_of_month_and_month(day_of_month: CronField, month: CronField) -> str:
    """Describe the day-of-month and month fields together.

    These read naturally as a unit, e.g. `on the 1st of every month` or
    `in January` when only the month is constrained.
    """
    if day_of_month.is_wildcard:
        return "" if month.is_wildcard else f"in {_describe_months(month)}"

    days = _join_with_and([_ordinal(value) for value in day_of_month.values])
    when = "of every month" if month.is_wildcard else f"of {_describe_months(month)}"
    return f"on the {days} {when}"


def _describe_months(field: CronField) -> str:
    """Render a month field as a comma-joined list of month names."""
    return _join_with_and([MONTH_NAMES[value - 1] for value in field.values])


# --------------------------------------------------------------------------- #
# Small utilities
# --------------------------------------------------------------------------- #

def _wildcard_step(field: CronField) -> int | None:
    """Return `n` if the field is exactly `*/n`, otherwise `None`."""
    if field.raw.startswith("*/"):
        return _parse_int(field.raw[2:], "step")
    return None


def _is_contiguous_range(field: CronField) -> bool:
    """True if the field was written as a single `low-high` range."""
    return "-" in field.raw and "," not in field.raw and "/" not in field.raw


def _join_values(values: list[int]) -> str:
    """Join integers for fallback descriptions, e.g. `5, 10, and 15`."""
    return _join_with_and([str(value) for value in values])


def _join_with_and(items: list[str]) -> str:
    """Join items with commas and an Oxford "and" before the last one."""
    if len(items) == 1:
        return items[0]
    if len(items) == 2:
        return f"{items[0]} and {items[1]}"
    return f"{', '.join(items[:-1])}, and {items[-1]}"


def _ordinal(number: int) -> str:
    """Return the ordinal form of a number, e.g. 1 -> `1st`, 22 -> `22nd`."""
    if 11 <= number % 100 <= 13:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(number % 10, "th")
    return f"{number}{suffix}"


# --------------------------------------------------------------------------- #
# Manual check
# --------------------------------------------------------------------------- #

if __name__ == "__main__":
    examples = [
        "* * * * *",
        "0 12 * * 1-5",
        "*/15 * * * *",
        "0 0 1 * *",
        "30 8 * * 1,3,5",
        "0 */2 * * *",
    ]
    for expression in examples:
        print(f"{expression:15} -> {parse_cron(expression).describe()}")
